// ── Stage 1: Build PLANNING prompt ─────────────────────────────────
const body = $input.first().json.body;
const pm = body.promptMeta || {};
const attachments = Array.isArray(body.attachments) ? body.attachments : [];
const attachmentMap = body.attachmentMap || {};
const slideCount = Number(pm.slideCount) || 0;
const slidePrompts = Array.isArray(pm.slidePrompts) ? pm.slidePrompts : [];
const systemPrompt = pm.systemPrompt || 'You are a planner. Return JSON.';

const trim = (v, max) => {
  if (typeof v !== 'string') return null;
  const t = v.trim();
  if (!t) return null;
  return t.length > max ? t.slice(0, max) + '…' : t;
};

let user = body.prompt || '';

if (slideCount > 0) {
  user += `\n\nDesired slide count: ${slideCount}`;
}

if (slidePrompts.length > 0) {
  user += '\n\nPer-slide hints from the user:';
  for (const sp of slidePrompts) {
    user += `\n- Slide ${sp.slideIndex + 1}: ${sp.prompt}`;
  }
}

// Keep stage 1 context small: focus on structure/content only.
if (attachments.length > 0) {
  user += '\n\nAvailable attachments (refs + short summaries):';
  for (const a of attachments) {
    const dim = (a.width && a.height) ? ` ${a.width}x${a.height}` : '';
    user += `\n- [${a.ref}] kind=${a.kind}, ${a.filename || ''}${dim}, mime=${a.mimeType || 'unknown'}`;
    const desc = trim(a.description, 220);
    const sum = trim(a.summary, 420);
    if (desc) user += `\n  Description: ${desc}`;
    if (sum) user += `\n  Summary: ${sum}`;
  }
}

return [{ json: {
  systemPrompt,
  userMessage: user,
  jobId: body.jobId,
  stage: 'planning',
  attempt: body.attempt || 1,
  secrets: body._secrets || {},
  attachmentMap,
  attachments,
}}];

