const planningResult = pm.planningResult;
const designInput = pm.designInput || null;
const systemPrompt = pm.systemPrompt || 'You are an art director. Return JSON.';

let user = 'Generate a design brief (JSON) based on the planning result and the user design brief below.';

user += '\n\nPlanning result (slides + content):\n' + JSON.stringify(planningResult, null, 2);

if (designInput) {
  user += '\n\nUser design brief:\n' + JSON.stringify(designInput, null, 2);
}

if (attachments.length > 0) {
  user += '\n\nAvailable attachments (consider visual treatment for image blocks):';
  for (const a of attachments) {
    const dim = (a.width && a.height) ? ` ${a.width}x${a.height}` : '';
    user += `\n- [${a.ref}] kind=${a.kind}${dim}`;
    if (a.description) user += `\n  Description: ${a.description}`;
  }
}

return [{ json: {
