let user = 'Generate the final HTML/CSS slides JSON. Strictly follow the design brief: layout class, background, decor, element classes per slide. Length and order of slides[] must match planning_result.slides exactly.';

user += '\n\nPlanning result:\n' + JSON.stringify(planningResult, null, 2);
user += '\n\nDesign brief:\n' + JSON.stringify(designBrief, null, 2);

if (attachments.length > 0) {
  user += '\n\nAvailable attachments (refs you may embed):';
  for (const a of attachments) {
    user += `\n- [${a.ref}] kind=${a.kind}, ${a.filename || ''}, mime=${a.mimeType || 'unknown'}`;
    if (a.description) user += `\n  Description: ${a.description}`;
