  let m;
  while ((m = re.exec(text)) !== null) {
    const idx = Number(m[1]);
    const block = m[2] || '';

    const title = (block.match(/Title:\s*\"([^\"]+)\"/) || [])[1] || `Слайд ${idx + 1}`;
    const subtitle = (block.match(/Subtitle:\s*\"([^\"]*)\"/) || [])[1] || '';

    const bullets = [];
    const bulletsMatch = block.match(/bullets?[^\[]*\[([\s\S]*?)\]/i);
    if (bulletsMatch) {
      const inner = bulletsMatch[1];
      for (const item of inner.split(/\n|,/)) {
        const cleaned = item.replace(/[\"\[\]]/g, '').trim();
        if (cleaned && cleaned.length < 200) bullets.push(cleaned);
      }
    }

    const speaker = (block.match(/speaker_notes?:\s*\"([\s\S]*?)\"/) || [])[1] || '';

    const blocks = [{ type: 'heading', text: title }];
    if (subtitle) blocks.push({ type: 'subtitle', text: subtitle });
    if (bullets.length >= 2) blocks.push({ type: 'bullets', items: bullets.slice(0, 6) });
    else blocks.push({ type: 'text', text: `Ключевые идеи про: ${title}.` });

    slides.push({ index: idx, title, subtitle, blocks, speaker_notes: speaker || '' });
  }

  // If nothing extracted, build a minimal skeleton
  const count = Number.isFinite(Number(desiredCount)) && Number(desiredCount) > 0 ? Number(desiredCount) : 5;
  if (slides.length === 0) {
    for (let i = 0; i < count; i++) {
      slides.push({
        index: i,
        title: i === 0 ? 'Титульный слайд' : `Слайд ${i + 1}`,
        subtitle: i === 0 ? 'Короткий подзаголовок' : '',
        blocks: [
          { type: 'heading', text: i === 0 ? 'Тема презентации' : `Раздел ${i}` },
          ...(i === 0 ? [{ type: 'subtitle', text: 'Короткий подзаголовок' }] : [{ type: 'text', text: 'Основная мысль слайда.' }]),
        ],
        speaker_notes: '',
      });
    }
  }

  // Normalize ordering and ensure indices 0..count-1
  slides.sort((a, b) => a.index - b.index);
  const out = [];
  for (let i = 0; i < (Number(desiredCount) || slides.length); i++) {
    const s = slides[i] || slides[slides.length - 1];
    out.push({ ...s, index: i });
  }
  return { slides: out };
}
