  }
  return null;
}


function extractJsonText(text) {
  if (typeof text !== 'string') return null;
  let t = text.trim();
  if (!t) return null;

  // Strip common code fences
  if (t.includes('```')) {
    t = t.replace(/```json\s*/gi, '').replace(/```\s*/g, '').trim();
  }

  // Fast path
  if (t.startsWith('{') || t.startsWith('[')) return t;

  // Heuristic: pick the largest JSON-looking substring
  const firstObj = t.indexOf('{');
  const lastObj = t.lastIndexOf('}');
  if (firstObj !== -1 && lastObj !== -1 && lastObj > firstObj) {
    return t.slice(firstObj, lastObj + 1);
  }

  const firstArr = t.indexOf('[');
  const lastArr = t.lastIndexOf(']');
  if (firstArr !== -1 && lastArr !== -1 && lastArr > firstArr) {
    return t.slice(firstArr, lastArr + 1);
  }

  return null;
}




function extractBalancedJson(text) {
  if (typeof text !== 'string') return null;
  let t = text.trim();
  if (!t) return null;

  if (t.includes('```')) {
    t = t.replace(/```json\s*/gi, '').replace(/```\s*/g, '').trim();
  }

  // Take the first opening bracket as the JSON root. Earlier versions tried
  // to be smart and locate the brace nearest to '"slides"', but that broke on
  // design output where the root object starts with '"theme"' first — the
  // heuristic then anchored on an inner brace (theme.fonts) and lost theme.
  let start;
  const obj = t.indexOf('{');
  const arr = t.indexOf('[');
  if (obj === -1 && arr === -1) return null;
  if (obj === -1) start = arr;
  else if (arr === -1) start = obj;
  else start = Math.min(obj, arr);

  const s = t.slice(start);
  const open = s[0];
  const close = open === '{' ? '}' : ']';

  let depth = 0;
  let inStr = false;
  let esc = false;

  for (let i = 0; i < s.length; i++) {
    const ch = s[i];
    if (inStr) {
      if (esc) {
        esc = false;
      } else if (ch === '\\') {
        esc = true;
      } else if (ch === '"') {
        inStr = false;
      }
      continue;
    }

    if (ch === '"') {
      inStr = true;
      continue;
    }

    if (ch === open) depth++;
    if (ch === close) {
      depth--;
      if (depth === 0) {
        return s.slice(0, i + 1);
      }
    }
  }

  return null;
}


const upstreamError = probeError(raw);

let content = '';
let output = null;
let errorMessage = null;

if (upstreamError) {
  errorMessage = 'LLM call failed: ' + upstreamError;
} else {
  const choice = raw?.choices?.[0] || {};
  const msg = choice.message || {};
  const finishReason = choice.finish_reason || '';
  const realContent = typeof msg.content === 'string' ? msg.content : '';
  const reasoningContent = typeof msg.reasoning_content === 'string' ? msg.reasoning_content : (typeof msg.reasoning === 'string' ? msg.reasoning : '');
  content = realContent || reasoningContent || '';
  if (finishReason === 'length') {
    errorMessage = 'LLM hit token limit (max_tokens) before returning JSON. Включите enable_thinking=false или увеличьте max_tokens.';
  } else if (!realContent && reasoningContent) {
    errorMessage = 'LLM returned only reasoning_content (thinking mode is on). Set chat_template_kwargs.enable_thinking=false or use a non-reasoning model.';
  } else if (!content || content.trim().length === 0) {
    errorMessage = 'LLM returned empty content';
  } else {    const jsonText = extractBalancedJson(content);
    try {
      if (!jsonText) {
        if (finishReason && finishReason !== 'stop') {
          throw new Error('LLM output truncated (finish_reason=' + finishReason + '). Попробуйте перезапустить этап или увеличить max_tokens.');
        }
        throw new Error('No JSON found in LLM output');
      }
      output = JSON.parse(jsonText);
      if (output === null || typeof output !== 'object') {
        throw new Error('LLM output is not a JSON object');
      }
      if (!output.slides || !Array.isArray(output.slides)) {
        throw new Error('Missing slides[] in refine output');
      }
      if (!output.theme || typeof output.theme !== 'object') output.theme = {};
      output.theme.fonts = [];
    } catch (e) {
      errorMessage = e.message || 'Failed to parse LLM JSON';
      output = null;
    }
  }
}

return [{ json: {
  jobId: prev.jobId,
  stage: prev.stage,
  output,
  errorMessage,
  llmRequest: { systemPrompt: prev.systemPrompt, userMessage: prev.userMessage },
  llmResponse: raw,
  secrets: prev.secrets,
  attachmentMap: prev.attachmentMap || {},
}}];

const errorData = $input.first().json;
let errorMessage = 'Unknown error occurred in pipeline';
let jobId = null;
let internalApiKey = null;
let stage = null;

try {
  if (errorData?.execution?.error?.message) {
    errorMessage = errorData.execution.error.message;
  }
} catch (e) {}

function tryExtractFrom(value) {
  if (!value || typeof value !== 'object') return;
  if (!jobId && typeof value.jobId === 'string') jobId = value.jobId;
  if (!stage && typeof value.stage === 'string') stage = value.stage;
  if (!internalApiKey && value._secrets && typeof value._secrets.internalApiKey === 'string') internalApiKey = value._secrets.internalApiKey;
  if (!internalApiKey && value.secrets && typeof value.secrets.internalApiKey === 'string') internalApiKey = value.secrets.internalApiKey;
}

function deepWalk(value, seen = new Set()) {
  if (!value || typeof value !== 'object' || seen.has(value)) return;
  seen.add(value);
  tryExtractFrom(value);
  if (jobId && internalApiKey && stage) return;
  if (Array.isArray(value)) { for (const item of value) { deepWalk(item, seen); if (jobId && internalApiKey && stage) return; } return; }
  for (const key of Object.keys(value)) { deepWalk(value[key], seen); if (jobId && internalApiKey && stage) return; }
}

try { deepWalk(errorData); } catch (e) {}

return [{ json: { jobId, errorMessage, internalApiKey, stage } }];

// Auto Planning (LLM-free fallback): creates a minimal planning_result so the user can review/edit.
const prev = $('Build Planning Prompt').first().json;
const body = $input.first().json;

// prev.userMessage contains the raw prompt text; keep only first line for title.
const topicLine = (prev.userMessage || '').split(/\n/)[0].trim() || 'Тема презентации';

// try to infer slideCount from userMessage if present
let count = 0;
const m = (prev.userMessage || '').match(/Desired slide count:\s*(\d+)/i);
if (m) count = Number(m[1]) || 0;
if (!count || count < 1) count = 5;

// Extract per-slide prompts (if present)
const hints = [];
const re = /- Slide\s+(\d+):\s*(.*)/g;
let mm;
while ((mm = re.exec(prev.userMessage || '')) !== null) {
  const idx = Number(mm[1]) - 1;
  const text = (mm[2] || '').trim();
  if (Number.isFinite(idx) && idx >= 0 && text) hints[idx] = text;
}

const slides = [];
for (let i = 0; i < count; i++) {
  const title = i === 0 ? topicLine : (hints[i] ? hints[i].slice(0, 80) : `Раздел ${i + 1}`);
  const subtitle = i === 0 ? 'Короткий подзаголовок (можно изменить)' : '';
  const blocks = [{ type: 'heading', text: title }];
  if (i === 0) blocks.push({ type: 'subtitle', text: subtitle });
  blocks.push({ type: 'text', text: hints[i] ? hints[i] : 'Опишите ключевую мысль этого слайда.' });

  slides.push({ index: i, title, subtitle, blocks, speaker_notes: '' });
}

return [{ json: {
  jobId: prev.jobId,
  stage: prev.stage,
  output: { slides },
  errorMessage: null,
  llmRequest: { systemPrompt: prev.systemPrompt, userMessage: prev.userMessage, mode: 'auto_planning' },
  llmResponse: null,
  secrets: prev.secrets,
  attachmentMap: prev.attachmentMap || {},
}}];
